int lower_bound(int n, int *a, int target)
/*@ With l
    Require
      0 <= n &&
      n <= INT_MAX &&
      Zlength(l) == n &&
      (forall (i: Z) (j: Z),
        (0 <= i && i <= j && j < n) => l[i] <= l[j]) &&
      IntArray::full(a, n, l)
    Ensure
      0 <= __return && __return <= n &&
      (forall (i: Z), (0 <= i && i < __return) => l[i] < target) &&
      ((__return == n) ||
       (__return < n && l[__return] >= target)) &&
      IntArray::full(a, n, l)
*/
{
    int left = 0;
    int right = n;
    int mid;

    while (left < right) {
        mid = left + (right - left) / 2;
        if (a[mid] < target) {
            left = mid + 1;
        } else {
            right = mid;
        }
    }

    return left;
}

#include "../../verification_stdlib.h"

/*@ Extern Coq (gcd_iterative_spec: Z -> Z -> Z -> Prop) */
/*@ Import Coq Require Import gcd_iterative */

int gcd_iterative(int a, int b)
/*@ Require
      0 <= a &&
      0 <= b &&
      (a != 0 || b != 0) &&
      emp
    Ensure
      gcd_iterative_spec(a@pre, b@pre, __return) && emp
*/
{
    int r;

    while (b != 0) {
        r = a % b;
        a = b;
        b = r;
    }

    return a;
}
